import { Outlet, Navigate } from "react-router-dom";

/**
 * ProtectedRoute checks if the user is logged in and optionally checks role.
 * Usage:
 * 1. <ProtectedRoute /> - allows any logged-in user
 * 2. <ProtectedRoute role="admin" /> - allows only admin users
 */
const ProtectedRoute = ({ role }) => {
  // Get user from localStorage
  const user = JSON.parse(localStorage.getItem("user"));

  // Not logged in
  if (!user) {
    return <Navigate to="/login" replace />;
  }

  // Role restricted
  if (role && user.role !== role) {
    return <Navigate to="/home" replace />; // Redirect non-admins to home
  }

  // Logged in and role ok
  return <Outlet />;
};

export default ProtectedRoutes;
